// Script Continued Below
function onSubmit() {

    if (g_form.getActionName() == 'cancel') {
        confirmTaskCancellation();
		return false;
    }

    function confirmTaskCancellation() {
		// u_cancellation_reason data type is HTML, but not using a control that shows it so strip off tags
		var formCancellationReason = g_form.getValue('u_cancellation_reason').replace(/<\/?[^>]+(>|$)/g, "");
		var formTaskSysId = g_form.getUniqueValue();
		var taskNumberShortDescription = g_scratchpad.taskerNumber + ': ' + g_form.getValue('short_description');
		var messageTitle = getMessage('cancel') + ' ' + taskNumberShortDescription + '?';

        // Use widget for Portal
        if (typeof spModal != 'undefined') {
            spModal.open({
                title: messageTitle,
                backdrop: 'static',
                widget: 'tasker_modal_cancel_tasks_prompt',
                widgetInput: {
                    'cancellationReason': formCancellationReason,
					'taskSysId': formTaskSysId
                },
                buttons: [],
                // Hide the <div> with class modal-footer that gets auto inserted from spModal, adds an element style
                footerStyle: {
                    'display': 'none'
                }
            }).then(function() {
                //jslog('numberofsubtasks');
            });
            return false;
        } else if (typeof spModal == 'undefined') {
            // For Platform use UI Page named: 
            var gm = new GlideModal('x_153465_discovert_cancel_task_prompt');
            gm.setTitle(messageTitle);
			gm.setPreference('sysparm_cancellationReason', formCancellationReason);
            gm.setPreference('sysparm_taskSysId', formTaskSysId);

            gm.setWidth(550);
            gm.render();
        }
    }
}
